def validate_cart_items(cart):
    valid_items = []
    for item in cart:
        if isinstance(item, CartItem):
            valid_items.append(item)
        else:
            print(f"Invalid item: {item}")
    return valid_items

def apply_discount_codes(user, cart):
    discount_codes = {"ADMIN10": DiscountCode("ADMIN10", 0.1, True), "USER5": DiscountCode("USER5", 0.05)}
    applied_codes = {}
    for code in discount_codes:
        if user.tier == 'admin' and discount_codes[code].admin_only:
            print(f"Admin-only discount {code} cannot be applied to user {user.name}")
        elif discount_codes[code].user_tiers and user.tier not in discount_codes[code].user_tiers:
            print(f"Discount code {code} is only for tier {discount_codes[code].user_tiers}")
        else:
            if code not in cart:
                print(f"Invalid discount code: {code}")
            else:
                applied_codes[code] = discount_codes[code]
    return applied_codes

def calculate_tax(cart, tax_rate):
    total_cost = sum(item.price for item in cart)
    tax_amount = total_cost * (tax_rate / 100)
    return tax_amount

