def checkout(user, cart, discount_codes=None, tax_rate=20):
    cart_items = validate_cart_items(cart)
    
    if discount_codes:
        applied_codes = apply_discount_codes(user, cart)
        
        # Apply discounts
        new_cart = [item for item in cart_items]
        for code, code_obj in applied_codes.items():
            new_cart = [item for item in new_cart if code not in item.name]
            total_cost = sum(item.price * (1 - code_obj.discount) for item in new_cart)
            
    else:
        new_cart = cart_items
        total_cost = sum(item.price for item in new_cart)

    
    tax_amount = calculate_tax(new_cart, tax_rate)
    payment_method = "Credit Card"
    
    order_record = process_payment(OrderRecord(new_cart, total_cost, tax_amount, payment_method), payment_method)
    
    return create_order_record(new_cart, tax_amount, payment_method)